--
-- Table structure for table `equipomedico`
--

DROP TABLE IF EXISTS `equipomedico`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipomedico` (
  `Serie` varchar(45) NOT NULL,
  `Marca` varchar(100) DEFAULT NULL,
  `Modelo` varchar(100) DEFAULT NULL,
  `Nombre` varchar(100) DEFAULT NULL,
  `YrCompra` year DEFAULT NULL,
  `Clave` varchar(45) DEFAULT NULL,
  `Piso` varchar(45) DEFAULT NULL,
  `Area` varchar(45) DEFAULT NULL,
  `ruta_equipo` varchar(255) DEFAULT NULL,
  `ruta_serie` varchar(255) DEFAULT NULL,
  `ruta_inventario` varchar(255) DEFAULT NULL,
  `Observaciones` varchar(255) DEFAULT NULL,
  `CartaObsolescencia` varchar(255) DEFAULT NULL,
  `Unidad` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`Serie`),
  CONSTRAINT `chk_equipomedico_piso` CHECK ((`Piso` in (_utf8mb4'Planta baja',_utf8mb4'Primero',_utf8mb4'Segundo',_utf8mb4'Tercero',_utf8mb4'Cuarto')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

