--
-- Table structure for table `mantenimientos`
--

DROP TABLE IF EXISTS `mantenimientos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mantenimientos` (
  `ServicioID` binary(16) NOT NULL,
  `FolioMantenimiento` varchar(45) DEFAULT NULL,
  `TipoServicio` varchar(45) DEFAULT NULL,
  `estado_postmant` varchar(45) DEFAULT NULL,
  `falla_reparada` varchar(1000) DEFAULT NULL,
  `PrecioServicio` varchar(45) DEFAULT NULL,
  `NumServicio` int DEFAULT NULL,
  `FechaServicio` date DEFAULT NULL,
  `ruta_orden` varchar(255) DEFAULT NULL,
  `Observaciones` varchar(255) DEFAULT NULL,
  `Serie` varchar(45) NOT NULL,
  `ContratoID` varchar(255) DEFAULT NULL,
  `ProveedorID` binary(16) DEFAULT NULL,
  `ReporteID` varchar(20) DEFAULT NULL,
  `GoogleEventID` varchar(255) DEFAULT NULL,
  `Responsablecorreo` varchar(255) DEFAULT NULL,
  `EstadoCalendario` varchar(45) DEFAULT NULL,
  `FechaSync` datetime DEFAULT NULL,
  `AnioServicio` year DEFAULT NULL,
  `SemanaServicio` int DEFAULT NULL,
  `InicioSemanaServicio` date DEFAULT NULL,
  `FinSemanaServicio` date DEFAULT NULL,
  `MesServicio` int DEFAULT NULL,
  `TipoServicioContrato` varchar(255) DEFAULT NULL,
  `CoberturaID` binary(16) DEFAULT NULL,
  PRIMARY KEY (`ServicioID`),
  UNIQUE KEY `uq_mantenimientos_serviciouuid` (`ServicioID`),
  KEY `Serie_idx` (`Serie`),
  KEY `ReporteID_idx` (`ReporteID`),
  KEY `FK_Mantenimiento_ContratoID_idx` (`ContratoID`),
  KEY `FK_Mantenimiento_ProveedorID_idx` (`ProveedorID`),
  KEY `FK_Mantenimiento_CoberturaID_idx` (`CoberturaID`),
  CONSTRAINT `FK_Mantenimiento_CoberturaID` FOREIGN KEY (`CoberturaID`) REFERENCES `cobertura_equipo` (`CoberturaID`),
  CONSTRAINT `FK_Mantenimiento_ContratoID` FOREIGN KEY (`ContratoID`) REFERENCES `contrato` (`ContratoID`),
  CONSTRAINT `FK_Mantenimiento_ProveedorID` FOREIGN KEY (`ProveedorID`) REFERENCES `proveedores` (`ProveedorID`),
  CONSTRAINT `FK_Mantenimiento_ReporteID` FOREIGN KEY (`ReporteID`) REFERENCES `reportes` (`ReporteID`),
  CONSTRAINT `FK_Mantenimiento_Serie` FOREIGN KEY (`Serie`) REFERENCES `equipomedico` (`Serie`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

