/*!50106 CREATE*/ /*!50117 DEFINER=`root`@`localhost`*/ /*!50106 EVENT `auto_recurso_propio_vencidas` ON SCHEDULE EVERY 1 DAY STARTS '2026-03-06 02:48:15' ON COMPLETION NOT PRESERVE ENABLE DO INSERT INTO cobertura_equipo (
    Serie,
    ContratoID,
    TipoCobertura,
    FechaInicio,
    FechaFin,
    ServiciosPlaneados,
    ServiciosxAnio
)
SELECT
    ce.Serie,
    NULL,
    'Recurso propio',
    DATE_ADD(ce.FechaFin, INTERVAL 1 DAY),
    NULL,
    NULL,
    NULL
FROM cobertura_equipo ce
WHERE ce.FechaFin IS NOT NULL
  AND ce.FechaFin < CURDATE()
  AND ce.FechaFin = (
      SELECT MAX(x.FechaFin)
      FROM cobertura_equipo x
      WHERE x.Serie = ce.Serie
        AND x.FechaFin IS NOT NULL
  )
  AND NOT EXISTS (
      SELECT 1
      FROM cobertura_equipo y
      WHERE y.Serie = ce.Serie
        AND (
            y.FechaFin IS NULL
            OR y.FechaInicio > ce.FechaFin
        )
  )
  AND NOT EXISTS (
      SELECT 1
      FROM cobertura_equipo z
      WHERE z.Serie = ce.Serie
        AND z.FechaInicio = DATE_ADD(ce.FechaFin, INTERVAL 1 DAY)
  ) */ ;;
